export const getGetReviewsUrl = (params: GetReviewsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/reviews?${stringifiedParams}`
    : `/api/reviews`;
};

export const getReviews = async (
  params: GetReviewsParams,
  options?: RequestInit,
): Promise<Review[]> => {
  return customFetch<Review[]>(getGetReviewsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetReviewsQueryKey = (params?: GetReviewsParams) => {
  return [`/api/reviews`, ...(params ? [params] : [])] as const;
};

export const getGetReviewsQueryOptions = <
  TData = Awaited<ReturnType<typeof getReviews>>,
  TError = ErrorType<unknown>,
>(
  params: GetReviewsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getReviews>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetReviewsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getReviews>>> = ({
    signal,
  }) => getReviews(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getReviews>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetReviewsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getReviews>>
>;
export type GetReviewsQueryError = ErrorType<unknown>;

/**
 * @summary Get reviews for a worker
 */

export function useGetReviews<
  TData = Awaited<ReturnType<typeof getReviews>>,
  TError = ErrorType<unknown>,
>(
  params: GetReviewsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getReviews>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetReviewsQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Submit a review for a worker
 */
export const getCreateReviewUrl = () => {
  return `/api/reviews`;
};

export const createReview = async (
  createReviewRequest: CreateReviewRequest,
  options?: RequestInit,
): Promise<Review> => {
  return customFetch<Review>(getCreateReviewUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(createReviewRequest),
  });
};

export const getCreateReviewMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createReview>>,
    TError,
    { data: BodyType<CreateReviewRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof createReview>>,
  TError,
  { data: BodyType<CreateReviewRequest> },
  TContext
> => {
  const mutationKey = ["createReview"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof createReview>>,
    { data: BodyType<CreateReviewRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return createReview(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type CreateReviewMutationResult = NonNullable<
  Awaited<ReturnType<typeof createReview>>
>;
export type CreateReviewMutationBody = BodyType<CreateReviewRequest>;
export type CreateReviewMutationError = ErrorType<unknown>;

/**
 * @summary Submit a review for a worker
 */
export const useCreateReview = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createReview>>,
    TError,
    { data: BodyType<CreateReviewRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof createReview>>,
  TError,
  { data: BodyType<CreateReviewRequest> },
  TContext
> => {
  return useMutation(getCreateReviewMutationOptions(options));
};

/**
 * @summary Get worker dashboard stats
 */
export const getGetWorkerDashboardUrl = (workerId: number) => {
  return `/api/workers/${workerId}/dashboard`;
};

export const getWorkerDashboard = async (
  workerId: number,
  options?: RequestInit,
): Promise<WorkerDashboard> => {
  return customFetch<WorkerDashboard>(getGetWorkerDashboardUrl(workerId), {
    ...options,
    method: "GET",
  });
};

export const getGetWorkerDashboardQueryKey = (workerId: number) => {
  return [`/api/workers/${workerId}/dashboard`] as const;
};

export const getGetWorkerDashboardQueryOptions = <
  TData = Awaited<ReturnType<typeof getWorkerDashboard>>,
  TError = ErrorType<unknown>,
>(
  workerId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getWorkerDashboard>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetWorkerDashboardQueryKey(workerId);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getWorkerDashboard>>
  > = ({ signal }) =>
    getWorkerDashboard(workerId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!workerId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getWorkerDashboard>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetWorkerDashboardQueryResult = NonNullable<
  Awaited<ReturnType<typeof getWorkerDashboard>>
>;
export type GetWorkerDashboardQueryError = ErrorType<unknown>;

/**
 * @summary Get worker dashboard stats
 */

export function useGetWorkerDashboard<
  TData = Awaited<ReturnType<typeof getWorkerDashboard>>,
  TError = ErrorType<unknown>,
>(
  workerId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getWorkerDashboard>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetWorkerDashboardQueryOptions(workerId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
